var creatures = [
  {id:1,emoji:"🦋",name:"Mothman",aka:"The Winged Harbinger",origin:"Point Pleasant, West Virginia, USA",region:"north_america",type:"cryptid",tags:["cryptid","humanoid"],threat:78,rarity:65,mapX:130,mapY:155,lore:"A towering winged humanoid with burning red eyes, the Mothman first appeared in 1966 near Point Pleasant, West Virginia. Standing over seven feet tall with a wingspan exceeding ten feet, it was sighted by over 100 witnesses in the thirteen months preceding the Silver Bridge collapse. Many researchers believe it is a harbinger of disaster, appearing before catastrophic events.",abilities:["Prophetic apparition before disasters","Flight at speeds exceeding 100mph","Hypnotic red eyes causing paralysis","Apparent immunity to conventional harm","Reported telepathic communication"],sightings:[{date:"NOVEMBER 15, 1966",text:"Roger and Linda Scarberry report a 'large flying man with ten-foot wings' following their car along Route 62 near the TNT Area. The creature kept pace with the vehicle at 100mph."},{date:"DECEMBER 15, 1967",text:"The Silver Bridge collapses, killing 46 people. Dozens of witnesses had reported Mothman sightings in the preceding weeks. Sightings in the area ceased entirely after the collapse."},{date:"SEPTEMBER 11, 2001",text:"Multiple witnesses reported a large winged humanoid figure above the Twin Towers in the hours before the attacks. Photographs emerged years later claiming to show the entity."}]},
  {id:2,emoji:"🦌",name:"Wendigo",aka:"The Hunger That Cannot Be Filled",origin:"Great Lakes & Northern Forests, North America",region:"north_america",type:"beast",tags:["beast","spirit","humanoid"],threat:97,rarity:72,mapX:120,mapY:130,lore:"Perhaps the most terrifying entity in Algonquian mythology, the Wendigo is a malevolent spirit that possesses humans who commit cannibalism, transforming them into monstrous beings of insatiable hunger. Standing over fifteen feet tall with emaciated frostbitten skin stretched over its bones, it roams boreal forests in winter, its howl mimicking the wind.",abilities:["Possession of humans who commit cannibalism","Shapeshifting and voice mimicry","Supernatural speed despite emaciated frame","Grows larger with each victim","Can induce Wendigo psychosis in nearby humans","Immunity to cold and frost"],sightings:[{date:"WINTER 1878",text:"Trapper Swift Runner confesses to consuming his entire family after claiming Wendigo possession. He is the first documented case of Wendigo psychosis in Western medical records."},{date:"JANUARY 1907",text:"Cree elder Jack Fiddler is arrested by the Royal Canadian Mounted Police for killing a Wendigo-possessed woman. He argues he was saving the community from a monster. He dies in custody."},{date:"FEBRUARY 2004",text:"A hunter near Kenora, Ontario reports hearing a sound like a woman screaming but wrong, and finding enormous bipedal tracks in the snow, each over three feet long, disappearing at a frozen lake's edge."}]},
  {id:3,emoji:"🐺",name:"Skinwalker",aka:"Yee Naaldlooshii",origin:"Navajo Nation, American Southwest, USA",region:"north_america",type:"spirit",tags:["spirit","humanoid"],threat:91,rarity:80,mapX:95,mapY:165,lore:"In Navajo tradition, a Skinwalker is a witch who has attained the power to transform into, possess, or disguise themselves as any animal. The transformation requires wearing the animal's pelt and committing an act of profound taboo. They are said to run faster than any vehicle, knock on windows to drive people mad, and spray corpse powder to cause illness.",abilities:["Shapeshifting into any animal","Voice mimicry of known persons","Supernatural speed exceeding vehicles","Corpse powder projection causing illness","Ability to read and control minds","Possession of animals and humans"],sightings:[{date:"1994–PRESENT",text:"Skinwalker Ranch, Utah: The Sherman family and subsequent owners report cattle mutilations, poltergeist activity, UFO sightings, and creature encounters over three decades. Purchased by Robert Bigelow for scientific study."},{date:"MARCH 2002",text:"A family driving on Highway 191 reports a creature running alongside their car at 60mph before leaping over the vehicle. Described as a man-shaped wolf with eyes that reflected like a mirror."},{date:"UNDATED",text:"Navajo police reports from the 1980s-90s describe multiple incidents of officers encountering creatures matching Skinwalker descriptions. Most reports were officially suppressed."}]},
  {id:4,emoji:"🦎",name:"Chupacabra",aka:"El Chupacabras",origin:"Puerto Rico & Latin America",region:"south_america",type:"cryptid",tags:["cryptid","beast"],threat:62,rarity:45,mapX:175,mapY:210,lore:"The Goat Sucker emerged in Puerto Rico in 1995 following an epidemic of livestock deaths. Animals were found completely drained of blood through small precise puncture wounds with no other injuries. Described as a reptilian bipedal creature with spines and glowing red eyes.",abilities:["Bloodless exsanguination through precise puncture wounds","Reported to move in large leaps","Night vision","Speed exceeding domestic animals"],sightings:[{date:"MARCH 1995",text:"Eight sheep found dead in Canóvanas, Puerto Rico, each completely drained of blood with three puncture wounds in the chest. Within weeks, over 150 animals were dead across the region."},{date:"AUGUST 1995",text:"Madelyne Tolentino reports a 4-5 foot tall creature with large red eyes, arms with claws, and a row of spines. Her sighting becomes the template for most subsequent reports."},{date:"JULY 2010",text:"A rancher in Cuero, Texas films what appears to be a hairless animal of unknown species feeding on a goat carcass. DNA analysis produces inconclusive results, ruling out known canid species."}]},
  {id:5,emoji:"🐕",name:"Black Shuck",aka:"Old Shuck",origin:"East Anglia, England",region:"europe",type:"spirit",tags:["spirit","beast","folklore"],threat:83,rarity:70,mapX:370,mapY:68,lore:"A spectral black dog the size of a calf that haunts the coastlines, graveyards, and lonely roads of East Anglia. Its name derives from the Old English scucca meaning demon. To meet its gaze brings death within the year. Its passage leaves no tracks.",abilities:["Immaterial form passing through solid objects","Death omen to those who meet its gaze","Leaves no physical tracks","Silent movement despite enormous size","Immunity to conventional harm"],sightings:[{date:"AUGUST 4, 1577",text:"Black Shuck reportedly bursts through the doors of St. Mary's Church in Blythburgh during a storm, killing two worshippers and causing the steeple to collapse. Scorch marks on the north door are still visible today."},{date:"SAME DATE, 1577",text:"Later that day, the creature appears at Holy Trinity Church in Blundeston, killing two more. Multiple eyewitness accounts were recorded by Abraham Fleming."},{date:"WINTER 1938",text:"A cyclist near Sheringham reports a dog the size of a calf running silently alongside him for three miles before vanishing at a crossroads. He reportedly died in an accident seven months later."}]},
  {id:6,emoji:"🎭",name:"Kuchisake-onna",aka:"The Slit-Mouthed Woman",origin:"Japan",region:"asia",type:"spirit",tags:["spirit","humanoid","folklore"],threat:86,rarity:55,mapX:735,mapY:88,lore:"A vengeful spirit who wanders at night wearing a surgical mask over her grotesquely slashed mouth. She approaches lone travelers asking Am I beautiful? Agreement reveals her wound. Only specific answers can delay or distract her.",abilities:["Supernatural speed overtaking fleeing victims","Shapeshifting to appear ahead of fleeing targets","Scissors or scythe hidden beneath clothing","Voice mimicry to lure victims","Cannot be outrun by conventional means"],sightings:[{date:"SPRING 1979",text:"Mass hysteria sweeps Japan as thousands of children report encounters. Schools hire escorts. Police go on alert. Kindergartens implement no-solitary-travel policies. Several municipalities report multiple independent identical accounts on the same night."},{date:"2004, SOUTH KOREA",text:"Reports emerge from Seoul of a masked woman asking the same question. A woman matching the description is struck by a car while pursuing a child. Authorities find nothing at the scene."},{date:"NOVEMBER 2007",text:"A construction team in Hokkaido reports excavating a burial site containing a woman interred with her mouth sewn shut, matching no known burial practice in the region."}]},
  {id:7,emoji:"👁️",name:"Dover Demon",aka:"Clapham Monster",origin:"Dover, Massachusetts, USA",region:"north_america",type:"cryptid",tags:["cryptid","humanoid"],threat:38,rarity:92,mapX:155,mapY:135,lore:"Over two nights in April 1977, three entirely separate witnesses reported an identical creature: hairless, roughly four feet tall, with a disproportionately large head, glowing orange eyes, and long thin fingers. It made no sound. It did not respond to being observed. The witnesses did not know each other and their sketches were virtually identical.",abilities:["Perfect stillness when observed","Apparent ability to climb smooth surfaces","Glowing eyes varying from orange to green","No discernible mouth or nose","No documented aggressive behavior"],sightings:[{date:"APRIL 21, 1977",text:"Bill Bartlett sees a creature on a stone wall on Farm Street. He initially believes it is a cat or dog, then realizes it is something else entirely. It turns and stares with large round orange eyes."},{date:"APRIL 22, 1977, MIDNIGHT",text:"John Baxter, walking home separately, encounters an identical creature. It stares at him briefly before moving into the woods. His sketch matches Bartlett's almost exactly."},{date:"APRIL 22, 1977, LATER",text:"William Taintor, a passenger in a car, spots the creature on the roadside for approximately 3 seconds. All three witnesses would later independently show signs of genuine distress when recounting the event."}]},
  {id:8,emoji:"👻",name:"Banshee",aka:"Bean Sídhe",origin:"Ireland & Scotland",region:"europe",type:"spirit",tags:["spirit","folklore","humanoid"],threat:28,rarity:58,mapX:355,mapY:62,lore:"A female spirit from Irish and Scottish Gaelic mythology whose keening wail foretells the imminent death of a family member. She appears as either a young woman in white, a middle-aged matron, or a haggard crone. She does not cause death. She mourns it before it happens.",abilities:["Prophetic keening foretelling death within 3 days","Wail strong enough to shatter glass","Ability to appear as young, middle-aged, or old simultaneously","Invisibility to those not of the target family"],sightings:[{date:"1801, COUNTY CLARE",text:"The O'Brien family reports hearing unearthly wailing for three consecutive nights. Their patriarch dies unexpectedly on the fourth day. Neighbors two miles distant reported identical sounds."},{date:"OCTOBER 1917",text:"A soldier's family in Connaught reports a wailing outside their home for three nights. They receive notice of his death in France two weeks later, occurring on the first night of the wailing."},{date:"1990s, MULTIPLE REPORTS",text:"Irish immigrant families in Boston, Chicago, and New York report hearing the keening around the time of deaths of relatives in Ireland, before receiving news. Cases documented by folklorist Patricia Lysaght."}]},
  {id:9,emoji:"❄️",name:"Yeti",aka:"Abominable Snowman",origin:"Himalayas, Nepal & Tibet",region:"asia",type:"beast",tags:["beast","cryptid"],threat:56,rarity:76,mapX:590,mapY:115,lore:"The Yeti is one of the most documented and searched-for cryptids in history. A large bipedal ape-like creature dwelling at elevations above 14,000 feet, it is considered sacred by Sherpa communities. DNA analysis of alleged Yeti samples has returned results suggesting an unknown or unclassified bear species.",abilities:["Exceptional strength — reported to lift boulders","Cold-weather adaptation at extreme altitudes","Speeds allowing it to outdistance mountaineers","Possible sonic disorientation of pursuers"],sightings:[{date:"NOVEMBER 1951",text:"Eric Shipton photographs enormous footprints at 19,000 feet on Menlung Glacier. Each print measures 13 inches wide. The prints continue for miles across the glacier."},{date:"JANUARY 1970",text:"Don Whillans and Dougal Haston observe a dark bipedal figure moving rapidly across a moonlit snowfield on Annapurna. Through binoculars, it appears far too large for a human or known animal."},{date:"MARCH 2019",text:"The Indian Army posts photographs of massive footprints near the Makalu base camp measuring 32x15 inches, consistent with a bipedal creature of enormous size."}]},
  {id:10,emoji:"🌊",name:"La Llorona",aka:"The Weeping Woman",origin:"Mexico & Latin America",region:"south_america",type:"spirit",tags:["spirit","humanoid","folklore"],threat:77,rarity:42,mapX:118,mapY:195,lore:"A tragic and terrifying figure in Latin American folklore, La Llorona drowned her children in a river after being abandoned by their father. Condemned to wander, she forever seeks her lost children along waterways and may substitute any child she finds. Her wail is said to stop hearts.",abilities:["Wailing that can cause cardiac arrest","Ability to appear as any woman from behind","Control over water and drowning","Compels children to approach water","Near invisibility in fog or rain"],sightings:[{date:"1550s, COLONIAL MEXICO CITY",text:"Spanish settlers document a woman's cry heard each night beginning at midnight. The sound is said to move against the wind and pass through walls. The dead are found each morning near the canals."},{date:"1930s–1950s",text:"Border patrol reports from the Texas-Mexico border document numerous instances of witnesses hearing a woman crying along the Rio Grande before discovering drowning victims."},{date:"ONGOING",text:"Emergency services in New Mexico, Texas, and throughout Central America continue to log calls annually reporting a crying woman near water before drowning incidents."}]},
  {id:11,emoji:"🎩",name:"Slender Man",aka:"Der Großmann",origin:"Global (Internet / Black Forest, Germany)",region:"europe",type:"humanoid",tags:["humanoid","cryptid","demon"],threat:68,rarity:40,mapX:420,mapY:70,lore:"Simultaneously one of the newest and oldest cryptids. Created as fiction in 2009 yet connected by researchers to 16th-century Black Forest records of Der Großmann. Slender Man erases memories, causes nosebleeds and paranoia, and reportedly appears more frequently the more one thinks about it.",abilities:["Memory erasure and reality distortion","Tentacle-like appendages from its back","Teleportation","Manifests more easily when believed in","Causes paranoia and blackouts in nearby humans","Mind control of proxies"],sightings:[{date:"16TH CENTURY, BLACK FOREST",text:"Bavarian woodcuts depict a tall faceless figure among the trees. Court records reference Der Großmann in multiple child disappearance cases. The records were rediscovered independently of the 2009 internet creation."},{date:"JUNE 2009",text:"Eric Knudsen posts fabricated photographs on forums. Within months, thousands of people begin reporting actual sightings matching the description."},{date:"MAY 31, 2014",text:"Two 12-year-old girls stab a classmate in Waukesha, Wisconsin, claiming they needed to prove Slender Man's existence. Psychiatrists note neither girl showed signs of prior delusion."}]},
  {id:12,emoji:"🐢",name:"Kappa",aka:"River Child",origin:"Japan",region:"asia",type:"spirit",tags:["spirit","aquatic","folklore"],threat:52,rarity:48,mapX:736,mapY:92,lore:"A water-dwelling yokai resembling a humanoid tortoise with a bowl of water on its head — the source of its power. It inhabits rivers and lakes, drowning travelers and livestock. Despite its danger, it is extraordinarily polite and bound by social custom — bowing causes it to spill its water and lose all power.",abilities:["Superior strength and swimming speed","Drowning of livestock and humans","Strategic intelligence","Bound by politeness — must return bows","Medical knowledge — can be bargained with"],sightings:[{date:"17TH CENTURY, ONGOING",text:"Warning signs about Kappa continue to appear near rivers throughout rural Japan, maintained by local governments — an extraordinary acknowledgment of folklore in modern public safety signage."},{date:"1980s, SAGA PREFECTURE",text:"Farmers report a creature stealing cucumbers and observed near irrigation canals, consistent with historical Kappa behavior. Local reports submitted to the municipality."},{date:"2009, ISHIKAWA PREFECTURE",text:"A construction crew excavating near a river uncovers a small mummified hand matching historical Kappa descriptions. Submitted for analysis, it remains uncategorized in museum archives."}]},
  {id:13,emoji:"🐙",name:"Kraken",aka:"Hafgufa",origin:"North Atlantic & Norwegian Sea",region:"europe",type:"beast",tags:["beast","aquatic","folklore"],threat:94,rarity:88,mapX:365,mapY:52,lore:"The Kraken of Norse mythology is so vast it was mistaken for an island by sailors who anchored upon it. When it dives, the suction pulls ships to the bottom. Modern researchers link it to the giant squid now confirmed to exist at over 40 feet, though historical descriptions far exceed any known cephalopod.",abilities:["Tentacles capable of encircling and sinking large ships","Suction powerful enough to create whirlpools","Camouflage matching the ocean surface","Size sufficient to be mistaken for an island","Commands schools of fish as advance warning"],sightings:[{date:"1752, BERGEN",text:"Erik Pontoppidan, Bishop of Bergen, publishes the first formal natural history description of the Kraken based on compiled sailor accounts. He estimates its body at 1.5 miles in circumference."},{date:"NOVEMBER 1861",text:"The French warship Alecton engages a massive squid-like creature in the Atlantic. They harpoon it but cannot retrieve it. A fragment of flesh is brought to the French Academy of Sciences."},{date:"2004, PACIFIC",text:"Japanese researchers photograph a living giant squid at 2,950 feet for the first time. Its eyes — the largest of any known animal — are the size of dinner plates."}]},
  {id:14,emoji:"🔥",name:"Ifrit",aka:"Efreet / Fire Djinn",origin:"Arabian Peninsula & Islamic World",region:"asia",type:"demon",tags:["demon","spirit","folklore"],threat:93,rarity:79,mapX:510,mapY:140,lore:"The Ifrit is among the most powerful of the Djinn in Islamic theology — created from smokeless fire, as humans are from clay. Unlike benevolent Djinn, the Ifrit are defiant, cunning, and malevolent. They can appear as towering beings of fire or take human form. The Quran references them directly — King Solomon commanded their labor.",abilities:["Flight and transportation across vast distances","Shapeshifting into any form including fire","Wish-granting at terrible cost","Strength vastly exceeding any human","Fire control and generation","Immunity to most physical harm"],sightings:[{date:"7TH CENTURY CE",text:"The Quran references an Ifrit offering to bring the throne of the Queen of Sheba to Solomon before he could rise from his seat — a display of supernatural speed across vast distance."},{date:"MEDIEVAL ERA, PERSIA",text:"The Thousand and One Nights documents hundreds of Ifrit encounters, many consistent with oral traditions predating the text by centuries."},{date:"ONGOING, SAUDI ARABIA",text:"Reports of Ifrit continue to be submitted to religious authorities. Some localities maintain active protocols for dealing with reported Djinn possession."}]},
  {id:15,emoji:"🌑",name:"Shadow People",aka:"Hat Man / The Watchers",origin:"Global",region:"north_america",type:"spirit",tags:["spirit","humanoid","demon"],threat:60,rarity:25,mapX:450,mapY:200,lore:"Encountered across every culture, continent, and era, Shadow People are two-dimensional humanoid figures of absolute darkness. The most common variant — Hat Man — wears a wide-brimmed fedora and overcoat. Unlike most paranormal entities, Shadow People appear to watch rather than act.",abilities:["Invisibility in peripheral vs direct sight","Apparent awareness of being observed","Reported to cause sleep paralysis","Phase through solid matter","Some variants feed on fear or life energy"],sightings:[{date:"ANCIENT EGYPT",text:"Egyptian funerary texts reference shadow entities they called shades that watched the dying. Hieroglyphic depictions show human-shaped shadows with no corresponding bodies."},{date:"2001, COAST TO COAST AM",text:"Art Bell's radio show receives an overwhelming response when he mentions Shadow People. Thousands of callers describe identical experiences, many using the same language without prior exposure to the term."},{date:"2015, SLEEP STUDY",text:"A Stanford sleep study inadvertently documents participants reporting shadow figure sightings during induced sleep paralysis, with 34% reporting a figure in a hat."}]},
  {id:16,emoji:"🐊",name:"Bunyip",aka:"Kianpraty",origin:"Australia",region:"australia",type:"beast",tags:["beast","aquatic","folklore"],threat:70,rarity:73,mapX:730,mapY:295,lore:"From the waterways of Australia, the Bunyip is described differently by every witness. Common features include a dog-like face, horse's tail, walrus tusks, and flippers. It bellows through the night and kills by drowning. Some accounts describe it as a shapeshifter; others as a remnant megafauna species from the Pleistocene.",abilities:["Powerful bellowing cry heard for miles","Exceptional swimming speed","Drowning of prey","Possible shapeshifting","Said to cause terror in nearby animals before appearing"],sightings:[{date:"1845, VICTORIA",text:"A skull of unknown species found at Kororoit Creek is displayed at the Australian Museum, causing widespread excitement as a potential Bunyip skull. It vanishes from records shortly after."},{date:"1890s, MULTIPLE",text:"Numerous settler reports from Victoria and New South Wales describe creatures emerging from swamps at night. One account describes a creature like a calf with a pug's head that bellowed for three days."},{date:"2010, QUEENSLAND",text:"Sonar sweeps of Lake Galilee return readings consistent with a large unidentified animate object. Documents obtained via freedom of information in 2018."}]},
  {id:17,emoji:"🧛",name:"Strigoi",aka:"The Undead / Romanian Vampire",origin:"Romania & Eastern Europe",region:"europe",type:"demon",tags:["demon","humanoid","folklore"],threat:90,rarity:67,mapX:448,mapY:82,lore:"The Strigoi is the origin entity behind all vampire mythology. Distinct from the romanticized Western vampire, Strigoi returns specifically to family members, killing methodically. It comes in two forms: the living sorcerer who projects their soul, and the undead corpse that rises to drain life.",abilities:["Blood and life-force draining","Shapeshifting into animals","Flight in spirit or physical form","Immunity to physical death after rising","Spread of condition through bite","Psychic connection to victims before rising"],sightings:[{date:"18TH CENTURY, SERBIA",text:"The cases of Petar Blagojevic and Arnold Paole — documented by Austrian military officers — describe exhumed corpses found preserved with fresh blood. Villagers were officially permitted to stake the bodies."},{date:"1801, TRANSYLVANIA",text:"Court records document an official investigation into a village where multiple residents died of a mysterious wasting illness. A corpse was exhumed and found in a state inconsistent with the burial date."},{date:"1990s, ROMANIA",text:"Several villages in rural Oltenia continue to practice exhumation and ritual treatment of corpses suspected of becoming Strigoi. Documented by anthropologists as a living tradition."}]},
  {id:18,emoji:"🦅",name:"Thunderbird",aka:"Binesi / Wakinyan",origin:"North America (Native Traditions)",region:"north_america",type:"spirit",tags:["spirit","beast","folklore"],threat:82,rarity:78,mapX:105,mapY:145,lore:"An enormous raptor-like being of supernatural power, the Thunderbird is a sacred figure across dozens of Native American traditions. Its wingbeats create thunder; its eyes flash lightning. Enormous bird sightings with wingspans reported at 10-20 feet continue across the American South and Midwest.",abilities:["Wingbeats producing thunder and storms","Eyes flashing lightning","Can carry off large animals — and humans","Messenger between sky and earth realms","Control over weather"],sightings:[{date:"APRIL 1977, LAWNDALE IL",text:"Two large birds with 10-15 foot wingspans attempt to carry off a 10-year-old boy. Multiple adult witnesses corroborate. No known bird species in the region matches the description."},{date:"JULY 2002, ALASKA",text:"Pilot John Bouker files an official report of a bird with a wingspan matching a small plane flying alongside his Cessna near Togiak. Multiple pilots and a state wildlife biologist report similar sightings that month."},{date:"ONGOING, ILLINOIS",text:"The Illinois Thunderbird is reported regularly along the Illinois River. More than 100 consistent eyewitness reports since 1948 describe a bird of impossible size."}]},
  {id:19,emoji:"🌿",name:"Green Man",aka:"Jack-in-the-Green / Foliate Head",origin:"Europe (Widespread)",region:"europe",type:"spirit",tags:["spirit","folklore","humanoid"],threat:30,rarity:60,mapX:400,mapY:78,lore:"A face of pure vegetation — leaves sprouting from the mouth, nose, and eyes — the Green Man appears carved in stone across thousands of churches and civic buildings from the 1st to 20th centuries. No written record explains why stonemasons across every culture compulsively carved this image.",abilities:["Control over plant growth","Ability to dissolve into forest","Induces compulsion to live in nature","Can animate vegetation in some traditions","Connection to seasonal death and rebirth"],sightings:[{date:"ONGOING, GLOBAL",text:"Over 100 Green Man carvings exist in Notre Dame Cathedral alone. They appear in Indian temples, Nepalese shrines, and Pre-Columbian structures — in cultures with no documented contact."},{date:"SUMMER 1972, DARTMOOR",text:"A hiker reports encountering a figure that seemed to be part of the trees that watched them from a clearing. When approached, it appeared to dissolve into the forest floor. No footprints were found."}]},
  {id:20,emoji:"🧊",name:"Amarok",aka:"The Giant Wolf",origin:"Arctic Canada & Greenland (Inuit)",region:"north_america",type:"beast",tags:["beast","folklore","spirit"],threat:85,rarity:82,mapX:110,mapY:75,lore:"In Inuit mythology, Amarok is a wolf of supernatural size that hunts humans who hunt alone at night — not out of malice, but to punish those who break the taboo of solitary night hunting. Said to be the size of a polar bear, it moves silently despite its size.",abilities:["Supernatural size and strength","Perfect silence despite enormous mass","Can sense solitary hunters across vast distances","Immune to cold","Commands wolf packs as extensions of its will"],sightings:[{date:"PRE-COLONIAL ERA, ONGOING",text:"Inuit oral tradition preserves thousands of Amarok accounts with remarkable consistency across geographically separated communities who had no contact. The descriptions are nearly identical from Alaska to Greenland."},{date:"WINTER 1987, BAFFIN ISLAND",text:"An Inuit hunter reports finding tracks in deep snow that transition from wolf prints to something far larger — each print 30 inches across — before ending abruptly at open tundra."}]},
  {id:21,emoji:"🌫️",name:"Will-o'-the-Wisp",aka:"Ignis Fatuus / Corpse Candle",origin:"British Isles & Europe",region:"europe",type:"spirit",tags:["spirit","folklore"],threat:42,rarity:38,mapX:378,mapY:64,lore:"Balls of ghostly light seen hovering over marshes and bogs at night, the Will-o'-the-Wisp leads travelers from safe paths to their doom in swamps. In Wales, they are corpse candles predicting death. Science explains some cases as oxidizing phosphine gas — but not all reported behaviors.",abilities:["Hovering flight mimicking a lantern","Luring of travelers away from safe paths","Apparent awareness and reactive movement to pursuit","Multiple simultaneous manifestations","Reported to change color: white, blue, red, green"],sightings:[{date:"ONGOING, SUFFOLK ENGLAND",text:"The Mardle Lights of the Norfolk Broads are reported annually and have been documented since at least the 17th century. Some manifestations move against the wind and react to observers."},{date:"2004, WALES",text:"A walker in the Brecon Beacons documents lights on video that hover, split into multiple units, and appear to react to his movements. Atmospheric scientists cannot replicate the conditions."}]},
  {id:22,emoji:"🦷",name:"Aswang",aka:"The Shape-Shifter",origin:"Philippines",region:"asia",type:"demon",tags:["demon","humanoid","spirit"],threat:89,rarity:62,mapX:700,mapY:185,lore:"The Aswang is the most feared supernatural entity in Filipino culture — a shape-shifter who appears as an ordinary person by day, transforming at night into a monstrous form. It specifically targets pregnant women, using its tongue to drain life from unborn children.",abilities:["Day-human, night-monster shapeshifting","Multiple creature forms","Detachable viscera that hunt independently","Targeting of pregnant women","Mimicry of voices to lure victims","Extraordinary strength and speed in monster form"],sightings:[{date:"1950s, PHILIPPINES",text:"CIA documents declassified in 1994 reveal that Psyops officers used Aswang mythology to psychologically defeat the Huk insurgency — draining rebel blood and leaving bodies to be found."},{date:"ONGOING, MINDANAO",text:"Hospitals in Mindanao continue to document cases of mass hysteria attributed to Aswang, with patients showing consistent physiological symptoms unexplained by medical science."},{date:"2012, QUEZON CITY",text:"A local councillor officially proposes a resolution warning residents about Aswang activity following multiple reports from the same neighbourhood. The resolution is tabled by the city council."}]},
  {id:23,emoji:"🌙",name:"Baba Yaga",aka:"The Iron-Toothed One",origin:"Eastern Europe & Russia",region:"europe",type:"spirit",tags:["spirit","humanoid","folklore","demon"],threat:80,rarity:72,mapX:475,mapY:68,lore:"One of the most complex entities in Slavic mythology, Baba Yaga defies simple classification. She is simultaneously villain, helper, nature deity, and death personification. She lives in a hut on chicken legs deep in the forest, surrounded by glowing skulls. She sits at the threshold between the living and dead worlds.",abilities:["Perfect knowledge of her forest domain","Flight in a mortar concealing her tracks","Ability to devour humans completely","Control over dawn, sun, and night","Gateway keeper between life and death","Prophecy and enforced quest-giving"],sightings:[{date:"PRE-SLAVIC ERA",text:"Scholars trace Baba Yaga to proto-Slavic shamanic traditions over 2,000 years old, with her hut on chicken legs potentially representing burial traditions where the deceased were placed in raised forest huts."},{date:"WORLD WAR I, RUSSIA",text:"Soldiers from rural Russia refuse to enter certain forest areas, citing Baba Yaga. Officers document the reports not as superstition but as effective denial of movement — the belief alone changing military positions."}]},
  {id:24,emoji:"💀",name:"La Santa Muerte",aka:"Holy Death / White Girl",origin:"Mexico",region:"south_america",type:"spirit",tags:["spirit","humanoid","folklore"],threat:55,rarity:35,mapX:115,mapY:195,lore:"La Santa Muerte is personified death itself, venerated by millions across Mexico and Central America. A skeletal female figure in robes, carrying a scythe and globe, she offers protection, healing, and safe passage regardless of one's sins. She is one of the fastest-growing new religious movements in the world.",abilities:["Command over the moment and manner of death","Power to grant or delay death","Protection of devotees","Safe passage of souls to the afterlife","No discrimination between sinners and saints"],sightings:[{date:"PRE-COLUMBIAN ERA",text:"Scholars trace her to Aztec death deities, particularly Mictecacihuatl, Queen of the Dead, syncretized with Catholic iconography after the Spanish conquest."},{date:"2001, TEPITO, MEXICO CITY",text:"Enriqueta Romero publicly displays a shrine to Santa Muerte outside her home — the first public altar. Within a decade, millions of devotees celebrate her feast days in every major city in the Americas."}]},
  {id:25,emoji:"🐍",name:"Nāga",aka:"Serpent Deity",origin:"India & Southeast Asia",region:"asia",type:"spirit",tags:["spirit","aquatic","folklore"],threat:65,rarity:60,mapX:585,mapY:155,lore:"Nāgas are powerful serpentine beings in Hindu, Buddhist, and Jain cosmology — divine in nature, living in underground kingdoms or deep waters. They can appear as humans, serpents, or human-serpent hybrids. They are guardians of water, treasure, and the underworld.",abilities:["Shapeshifting between serpent and human form","Control over rain and waterways","Venom capable of killing gods","Guardianship over underground treasure","Sacred temples require their appeasement"],sightings:[{date:"ANNUAL, NAGA PANCHAMI",text:"Hundreds of millions of Hindus observe Naga Panchami, leaving offerings at snake holes and temples. In parts of rural India, live cobras are brought into homes as honored guests."},{date:"1973, MEKONG RIVER",text:"Soldiers on the Thai-Laos border report enormous water creatures in the Mekong River, consistent with Nāga traditions of the region. Photographs taken by Thai soldiers are still disputed."}]},
  {id:26,emoji:"🧊",name:"Qallupilluit",aka:"Qalupalik",origin:"Arctic Canada & Greenland (Inuit)",region:"north_america",type:"spirit",tags:["spirit","aquatic","folklore"],threat:74,rarity:77,mapX:125,mapY:80,lore:"An Inuit spirit that hides beneath the sea ice, waiting for children who stray too close to the water's edge. She wears a traditional coat and collects disobedient children to raise them under the ice. The legends serve a crucial survival function, teaching children to avoid thin ice.",abilities:["Perfect concealment beneath ice","Silence and stealth near water","Can create knocking sounds under ice","Abduction of children into underwater realm","Time distortion — trapped children age differently"],sightings:[{date:"PRE-COLONIAL ERA, ONGOING",text:"The remarkable consistency of Qallupilluit descriptions across thousands of miles of Arctic communities — with no documented contact between them — suggests an ancient common cultural origin or genuinely shared experience."}]},
  {id:27,emoji:"🐘",name:"Grootslang",aka:"Great Snake",origin:"South Africa",region:"africa",type:"beast",tags:["beast","aquatic"],threat:88,rarity:90,mapX:450,mapY:290,lore:"From the Richtersveld desert of South Africa, the Grootslang is said to be a primordial creature combining the power of an elephant and a serpent. It lives in a cave called the Wonder Hole and guards vast diamond hordes. It can be bribed with gems to release trapped prey.",abilities:["Immense physical strength combining elephant and serpent","Ability to swallow elephants","Gem-hoarding intelligence","Apparent immortality","Can be bargained with using precious stones"],sightings:[{date:"1917, RICHTERSVELD",text:"English businessman Peter Grayson disappears in the Richtersveld while searching for the Grootslang's cave. Rescue parties find his camp abandoned with no signs of struggle or tracks leading away."},{date:"ONGOING, SOUTH AFRICA",text:"Local communities maintain detailed knowledge of the Grootslang's territory and warn outsiders. Geologic surveys of the region have noted cave systems of exceptional depth that researchers have declined to fully explore."}]},
  {id:28,emoji:"🌺",name:"Pontianak",aka:"Kuntilanak",origin:"Malaysia & Indonesia",region:"asia",type:"demon",tags:["demon","spirit","humanoid"],threat:87,rarity:65,mapX:665,mapY:205,lore:"A vampiric spirit of Southeast Asian mythology — the ghost of a woman who died during childbirth. She appears as a beautiful woman in a white dress, often near banana trees, whose beauty conceals a rotting back. She kills by driving her long nails into the necks or stomachs of victims and tearing out organs. The scent of frangipani flowers announces her presence.",abilities:["Appears as beautiful woman to lure victims","Lethal fingernails that tear organs","Ability to fly","Shapeshifting to reveal her true rotting form","Can be controlled by driving a nail into her neck","Attracted to blood — particularly of newborns"],sightings:[{date:"ONGOING, MALAYSIA",text:"Construction sites across Malaysia regularly halt work due to reported Pontianak sightings. Workers cite the scent of frangipani at night and sounds of an infant crying before a beautiful woman is seen."},{date:"2005, SINGAPORE",text:"A security guard files a police report after encountering a woman in white near a canal who vanished when he looked directly at her. The report joins dozens of similar accounts from the same stretch of road."},{date:"UNDATED, BORNEO",text:"Midwives in rural Borneo continue to perform traditional rituals involving broken glass, needles, and betel leaves placed under a house during labor to prevent a Pontianak from forming."}]},
  {id:29,emoji:"🐉",name:"Ryūjin",aka:"Dragon King of the Sea",origin:"Japan",region:"asia",type:"spirit",tags:["spirit","aquatic","folklore"],threat:88,rarity:95,mapX:745,mapY:100,lore:"The Dragon King of the Sea in Japanese mythology, Ryūjin dwells in a coral palace beneath the ocean. He controls the tides using magical tide jewels, can transform into human form, and is the ancestor of the Japanese imperial family. Time passes differently in his domain.",abilities:["Control over ocean tides and storms","Shapeshifting between dragon and human form","Command over all marine creatures","Time distortion within his palace","Ancestor of Japanese imperial bloodline"],sightings:[{date:"LEGENDARY ERA",text:"The hero Urashima Tarō visits Ryūjin's palace, spending what feels like days — returning to find three hundred years had passed on the surface world."},{date:"8TH CENTURY AD",text:"Chronicles of the Nihon Shoki record Empress Jingū receiving the tide jewels from Ryūjin before her invasion of Korea, using them to drain and flood the sea against enemy fleets."}]},
  {id:30,emoji:"🧿",name:"Evil Eye",aka:"Mal de Ojo / Nazar",origin:"Mediterranean, Middle East & Latin America",region:"europe",type:"spirit",tags:["spirit","folklore"],threat:45,rarity:20,mapX:440,mapY:105,lore:"Not a creature but an entity of pure malevolent intent — a curse transmitted through a gaze filled with envy or malice. Documented in ancient Mesopotamian texts over 5,000 years old and referenced in the Bible, Quran, and classical Greek sources, the Evil Eye is the most globally pervasive supernatural belief in human history.",abilities:["Transmission through envious gaze","Causes illness, misfortune, and death","Particularly potent against children and livestock","Can be transmitted unknowingly","Countered by specific talismans in each culture"],sightings:[{date:"3000 BCE, MESOPOTAMIA",text:"Cuneiform tablets from ancient Akkad describe the eye disease — a malevolent gaze that causes physical wasting in victims. Counter-rituals are prescribed for the first time in recorded human history."},{date:"ONGOING, GLOBAL",text:"The Nazar blue eye amulet is among the world's most produced objects. Over 100 million are made annually in Turkey alone — sold as protection to believers across all major religions."}]},
  {id:31,emoji:"🦕",name:"Loch Ness Monster",aka:"Nessie",origin:"Loch Ness, Scotland",region:"europe",type:"cryptid",tags:["cryptid","aquatic"],threat:40,rarity:82,mapX:368,mapY:55,lore:"The most famous cryptid in the world, Nessie is said to inhabit the deep dark waters of Loch Ness in the Scottish Highlands. Described as a massive plesiosaur-like creature with a long neck, small head, and humped back. The loch is 755 feet deep and so murky that sonar sweeps have returned massive unexplained readings that scientists cannot account for.",abilities:["Deep water submersion for extended periods","Sonar evasion in murky water","Possible speed despite enormous size","Reported ability to surface silently"],sightings:[{date:"565 AD",text:"Saint Columba reportedly encounters a beast in the River Ness, commanding it to retreat in the name of God. The creature obeys — the earliest recorded sighting in history."},{date:"MAY 2, 1933",text:"John Mackay and his wife report a tremendous upheaval in the loch while driving along the shore. The Inverness Courier publishes the account, sparking worldwide fascination."},{date:"1934",text:"The famous Surgeon's Photograph appears to show a long-necked creature in the loch. It dominates headlines globally for decades before being revealed as a hoax in 1994 — though many researchers dispute this conclusion."}]},
  {id:32,emoji:"👽",name:"Flatwoods Monster",aka:"Braxton County Monster / Phantom of Flatwoods",origin:"Flatwoods, West Virginia, USA",region:"north_america",type:"cryptid",tags:["cryptid","humanoid"],threat:65,rarity:95,mapX:133,mapY:152,lore:"On September 12, 1952, six children and a local woman encountered something in the hills of Flatwoods, West Virginia that defied explanation. A towering figure over 10 feet tall with a blood-red face, glowing green eyes, and a dark spade-shaped head hovered above the ground amid a cloud of mist that burned their eyes and throats. The encounter lasted only seconds but left witnesses with lasting physical symptoms.",abilities:["Hovering flight without visible propulsion","Emission of nauseating mist causing illness","Glowing eyes visible from great distance","Apparent cloaking in fog or haze","Physical symptoms induced in witnesses at range"],sightings:[{date:"SEPTEMBER 12, 1952",text:"The Flatwoods encounter: Kathleen May, her two sons, and four other boys investigate a bright object that fell on a nearby hill. They encounter a hissing, glowing creature near a pulsing red ball of light. All witnesses later suffer from vomiting and throat irritation consistent with chemical exposure."},{date:"SEPTEMBER 13, 1952",text:"A reporter investigating the site the next day finds skid marks and an oily residue on the ground. A local farmer reports seeing a similar figure the same night a mile away, without knowledge of the first encounter."},{date:"ONGOING",text:"Flatwoods, West Virginia maintains a museum dedicated to the encounter. The town embraces the legend, and investigators continue to note the unusual concentration of UFO sightings in Braxton County."}]},
  {id:33,emoji:"🦶",name:"Bigfoot",aka:"Sasquatch / Yowie",origin:"Pacific Northwest, USA & Canada",region:"north_america",type:"cryptid",tags:["cryptid","beast"],threat:48,rarity:55,mapX:75,mapY:125,lore:"The most reported cryptid in North America, Bigfoot is described as a massive bipedal ape standing 7-10 feet tall and weighing up to 800 pounds. Covered in dark brown or reddish hair, it leaves footprints up to 24 inches long. Over 10,000 sightings have been reported since the 1800s across every US state except Hawaii. Its existence remains officially unconfirmed despite decades of investigation.",abilities:["Extraordinary strength — reported to uproot trees","Speed exceeding Olympic sprinters despite size","Infrasound emission causing nausea and panic in witnesses","Apparent intelligence allowing evasion of all capture attempts","Possible ability to move silently despite enormous size"],sightings:[{date:"OCTOBER 1967",text:"Roger Patterson and Bob Gimlin film a large bipedal creature walking along Bluff Creek in Northern California. The Patterson-Gimlin film remains the most analyzed piece of cryptid footage in history. No definitive proof of a costume or hoax has ever been established."},{date:"1969, SKOOKUM MEADOWS",text:"A massive body cast is made in Skookum Meadows, Washington — showing the impression of a massive creature that lay on its side to reach bait. Primate experts confirm it is not consistent with any known animal."},{date:"AUGUST 2000",text:"The Skookum Cast expedition, organized by the BFRO, recovers a full body impression measuring over 3.5 feet across. Hair samples collected at the site return inconclusive DNA results — not matching any known species."}]},

  {id:34,emoji:"🐈",name:"Cait Sith",aka:"Fairy Cat",origin:"Scottish & Irish Highlands",region:"europe",type:"spirit",tags:["spirit","beast","folklore"],threat:55,rarity:75,mapX:363,mapY:57,lore:"A large black cat with a white spot on its chest from Scottish and Irish mythology — potentially the spirit of a transformed witch. It haunts the Scottish Highlands and is said to steal the souls of the recently dead before they can be claimed by God. Highlands communities would hold all-night vigils called Late Wakes to distract the Cait Sith from the body of the deceased.",abilities:["Soul theft from unprotected corpses","Shapeshifting between cat and witch form","Ability to bless or curse a household","Grants wishes in exchange for milk on Samhain","Impossible speed and stealth"],sightings:[{date:"MEDIEVAL ERA, SCOTLAND",text:"Highland communities maintained strict Late Wake traditions specifically to deter the Cait Sith, including riddle contests, music, and fire — all documented in early Scottish church records as pagan practices to be suppressed."},{date:"1800s, ISLE OF SKYE",text:"Numerous accounts describe an enormous black cat watching funerals from hillsides, disappearing before anyone could approach. Local tradition held it was assessing whether the soul was worth taking."},{date:"ONGOING",text:"The Beast of Exmoor and various British Big Cat sightings are sometimes linked by researchers to the Cait Sith tradition — suggesting a possible basis in a genuine large cat species that once roamed Britain."}]},

  {id:35,emoji:"🌋",name:"Pele",aka:"She Who Shapes the Sacred Land",origin:"Hawaii, USA",region:"north_america",type:"spirit",tags:["spirit","folklore","humanoid"],threat:92,rarity:70,mapX:60,mapY:190,lore:"The Hawaiian goddess of volcanoes, fire, lightning, and wind, Pele is simultaneously creator and destroyer. She is said to reside in the Kilauea volcano on the Big Island and is considered the creator of the Hawaiian Islands themselves. She appears to mortals as either a beautiful young woman or a withered old crone — both forms are tests of a stranger's kindness.",abilities:["Control over volcanic eruptions and lava flows","Shapeshifting between young and old woman","Command over fire, lightning, and wind","Ability to create and destroy land itself","Cursing those who steal volcanic rock"],sightings:[{date:"ONGOING, BIG ISLAND",text:"Thousands of tourists report encounters with an old woman hitchhiking near Kilauea who vanishes from locked cars. The National Park Service receives regular reports. Local tradition strongly advises picking her up."},{date:"1983–PRESENT",text:"The ongoing Kilauea eruption — one of the longest in recorded history — is interpreted by Native Hawaiian practitioners as Pele actively reshaping her domain. Lava flows have destroyed entire communities while inexplicably sparing others."},{date:"ANNUALLY",text:"The Hawaii Volcanoes National Park receives hundreds of packages annually from tourists returning stolen lava rock, accompanied by letters describing the terrible luck that followed taking it — attributed to Pele's curse."}]},

  {id:36,emoji:"🕷️",name:"Anansi",aka:"Ananse / Spider God",origin:"West Africa & Caribbean",region:"africa",type:"spirit",tags:["spirit","folklore","humanoid"],threat:35,rarity:65,mapX:400,mapY:240,lore:"Anansi is the trickster spider god of the Akan people of West Africa, keeper of all stories in the world. He obtained all stories from the Sky God Nyame by capturing the hornets, the python, and the leopard through cunning alone. Brought to the Caribbean through the slave trade, Anansi stories became a form of resistance and coded survival knowledge — making him one of the most culturally important supernatural beings in the African diaspora.",abilities:["Master of deception and strategy","Web-spinning of supernatural strength and complexity","Shapeshifting between spider and human form","Keeper and controller of all stories","Can outwit any being regardless of power","Spreads confusion and chaos as defense"],sightings:[{date:"ANCIENT ERA, GHANA",text:"Anansi stories form the core of Akan oral tradition, with some narratives estimated to be over 3,000 years old. They spread to every culture touched by the West African diaspora."},{date:"COLONIAL ERA, CARIBBEAN",text:"Enslaved Africans preserved Anansi stories as coded messages about resistance, escape, and survival. British colonial authorities attempted to suppress the stories, recognizing their subversive power."},{date:"ONGOING, GLOBAL",text:"Anansi remains a living cultural figure across West Africa, the Caribbean, and among the African diaspora worldwide — appearing in modern literature, film, and music as a symbol of wit overcoming power."}]},

  {id:37,emoji:"🌊",name:"Leviathan",aka:"The Serpent of the Deep",origin:"Ancient Near East / Biblical",region:"europe",type:"beast",tags:["beast","aquatic","demon"],threat:99,rarity:99,mapX:490,mapY:120,lore:"The Leviathan is a primordial sea monster described in the Hebrew Bible — a creature so vast and terrible that only God can restrain it. Described as a fire-breathing dragon of the sea with scales like shields, it is the embodiment of chaos itself. In later Jewish tradition, Leviathan and Behemoth will battle at the end of days, and the righteous will feast on their flesh.",abilities:["Fire and smoke breathing from the deep","Scales impenetrable to any weapon","Ability to churn the sea into boiling foam","Embodiment of primordial chaos","Size so vast it can encircle the world","Only divine power can contain or defeat it"],sightings:[{date:"ANCIENT ERA",text:"The Book of Job describes Leviathan in extraordinary anatomical detail across 20 verses — suggesting the description was based on something real that ancient peoples had encountered or heard credible accounts of."},{date:"MEDIEVAL ERA",text:"Medieval cartographers marked unknown ocean regions with Leviathan illustrations. Sailors' accounts of massive sea creatures were interpreted as genuine Leviathan sightings by church authorities."},{date:"ONGOING",text:"The colossal squid, giant oarfish, and whale shark continue to be cited as possible bases for the Leviathan myth. The deep ocean remains less explored than the surface of Mars."}]},

  {id:38,emoji:"🧠",name:"Loveland Frogman",aka:"The Loveland Frog",origin:"Loveland, Ohio, USA",region:"north_america",type:"cryptid",tags:["cryptid","humanoid","aquatic"],threat:30,rarity:88,mapX:138,mapY:148,lore:"A bipedal frog-like creature standing 3-4 feet tall, the Loveland Frogman has been reported along the Little Miami River near Loveland, Ohio since 1955. Described with leathery skin, a frog-like face, and an upright posture, it has been encountered by police officers on two separate occasions. In one encounter, it raised a wand-like object that emitted sparks.",abilities:["Amphibious — equally capable on land and in water","Reported wand emitting light or sparks","Nighttime activity and evasion","Remarkable speed entering water","Apparent intelligence — has not displayed aggression"],sightings:[{date:"1955, LOVELAND OHIO",text:"A businessman reports seeing three frog-like creatures standing upright under a bridge on the Little Miami River. One raises a bar above its head that emits sparks. He watches for several minutes before driving away."},{date:"MARCH 1972",text:"Police officer Ray Shockey encounters a frog-like creature on the road near Loveland at night. It rises from a crouching position and leaps over the guardrail into the river. A second officer investigates and sees a similar creature days later."},{date:"AUGUST 2016",text:"A couple playing Pokemon Go near Lake Isabella reports a massive frog walking upright and swinging its arms. They photograph it before it enters the water. The image is disputed but remains unexplained."}]},

  {id:39,emoji:"🎪",name:"Spring Heeled Jack",aka:"The Terror of London",origin:"London & Victorian England",region:"europe",type:"humanoid",tags:["humanoid","demon","cryptid"],threat:76,rarity:85,mapX:375,mapY:67,lore:"A terrifying figure that haunted Victorian England from 1837 to 1904, Spring Heeled Jack could leap over buildings in a single bound, breathe blue and white flames, and had claws of iron. Described as a tall thin figure with a pointed face, glowing red eyes, and a cape, it attacked women across London, the Midlands, and Scotland. It evaded every attempt at capture for nearly 70 years.",abilities:["Leaping to rooftop height in a single bound","Blue and white fire breathing","Iron claws capable of tearing thick clothing","Apparent immunity to firearms — shot multiple times with no effect","Speed and agility far exceeding any human","Reported to laugh maniacally during attacks"],sightings:[{date:"OCTOBER 1837",text:"Jane Alsop answers her door to a figure claiming to be a policeman who has caught Spring Heeled Jack. He throws back his cloak to reveal glowing eyes and breathes blue flame into her face before attacking. She is rescued by her sister."},{date:"FEBRUARY 1838",text:"Lucy Sales is attacked by a figure matching the same description near her home. Her father and neighbors pursue but it escapes by leaping over a 9-foot wall with apparent ease."},{date:"1904, EVERTON",text:"Spring Heeled Jack's last reported appearance — seen leaping between rooftops in Everton, Liverpool by dozens of witnesses simultaneously. It bows to the crowd before bounding away and is never credibly reported again."}]},

  {id:40,emoji:"🐊",name:"Ogopogo",aka:"Naitaka / Lake Demon",origin:"Lake Okanagan, British Columbia, Canada",region:"north_america",type:"cryptid",tags:["cryptid","aquatic"],threat:58,rarity:78,mapX:80,mapY:115,lore:"Canada's answer to the Loch Ness Monster, Ogopogo inhabits Lake Okanagan in British Columbia. Indigenous Syilx peoples knew it as Naitaka — a malevolent lake demon requiring offerings of small animals before crossing the water. The lake is 84 miles long and 761 feet deep. Unlike Nessie, Ogopogo has been reported by hundreds of credible witnesses simultaneously, and multiple video recordings exist that remain unexplained.",abilities:["Deep water submersion in extremely cold temperatures","Speed sufficient to create visible wake","Reported ability to capsize small watercraft","Apparent awareness of observers — active avoidance","Multiple humps visible when surfacing"],sightings:[{date:"1872",text:"Susan Allison becomes one of the first settlers to report the creature, describing a large animal in the lake that caused her horse to panic. Indigenous guides refuse to cross the lake without making offerings."},{date:"JULY 1974",text:"Over 30 witnesses simultaneously observe a large creature with multiple humps moving across the lake near Kelowna. The sighting lasts several minutes. Witnesses include a retired judge and a local politician."},{date:"2011",text:"A video taken from a houseboat appears to show a large dark shape beneath the surface moving independently of the current. The footage is submitted to scientists who cannot identify the object as any known species."}]},
  {id:41,emoji:"🧛",name:"Vampire",aka:"The Undead / Children of Cain",origin:"Global",region:"europe",type:"demon",tags:["demon","humanoid","folklore"],threat:85,rarity:35,mapX:445,mapY:80,lore:"Among the oldest and most universally feared supernatural predators, vampires are reanimated corpses that feed on the blood of the living. Unlike romanticized modern portrayals, true vampires are apex predators with superhuman strength, speed, and regeneration. They organize in nests, hunt in packs, and are led by an Alpha — the first and most powerful of their kind, created at the dawn of humanity.",abilities:["Superhuman strength and speed","Rapid cellular regeneration","Retractable fangs delivering lethal bite","Heightened senses — can smell blood from miles away","Near immortality unless beheaded","Pack hunting coordination"],sightings:[{date:"1721, EAST PRUSSIA",text:"Official government investigations into vampire attacks sweep Eastern Europe. Bodies are exhumed and staked by order of local authorities. Austrian officers file detailed reports of preserved corpses with fresh blood — the first official government acknowledgment of vampire activity."},{date:"1819, ENGLAND",text:"John Polidori publishes The Vampyre, based on accounts collected during travels in Eastern Europe. He insists the creature described is not fictional."},{date:"ONGOING, GLOBAL",text:"Unexplained exsanguination cases continue to be reported worldwide. Medical examiners note a pattern of bloodless bodies with puncture wounds to the neck that appear in clusters before stopping abruptly — consistent with a nest relocating."}]},

  {id:42,emoji:"🐺",name:"Werewolf",aka:"Lycanthrope / Moon Cursed",origin:"Global",region:"europe",type:"beast",tags:["beast","humanoid","folklore"],threat:88,rarity:42,mapX:430,mapY:75,lore:"A human being cursed or infected with lycanthropy — the ability to transform into a wolf or wolf-human hybrid. Unlike folklore, the transformation is not limited to the full moon in documented cases; it is triggered by strong emotion, the scent of blood, or deliberate will in older specimens. Werewolves feed on human hearts, which they crave above all else. The infection spreads through saliva.",abilities:["Full or partial transformation at will in older specimens","Superhuman strength — capable of tearing through steel","Heightened senses far beyond any known animal","Rapid healing of wounds except those caused by silver","Transmission of lycanthropy through bite","Compulsive craving for human hearts"],sightings:[{date:"1764–1767, FRANCE",text:"The Beast of Gévaudan terrorizes the Auvergne region of France, killing over 100 people. Described as wolf-like but walking upright, it shrugs off musket fire that would kill any normal animal. King Louis XV sends his best hunters. The creature is never satisfactorily identified."},{date:"1810, BEDBURG GERMANY",text:"Peter Stumpp is tried and executed for werewolf crimes after confessing to transformations and multiple killings. The trial records describe details consistent with lycanthropic behavior that cannot be explained by known mental illness."},{date:"ONGOING",text:"Clusters of exsanguinated deer and livestock with massive claw marks — far beyond any known predator — continue to be reported in rural areas globally. Local hunters consistently describe a large bipedal animal before the attacks cease as suddenly as they began."}]},

  {id:43,emoji:"👤",name:"Shapeshifter",aka:"Skin-Walker / Doppelganger",origin:"Global",region:"north_america",type:"cryptid",tags:["cryptid","humanoid","demon"],threat:82,rarity:50,mapX:200,mapY:160,lore:"A creature that can perfectly replicate the appearance of any human — copying their face, voice, fingerprints, and even memories drawn from physical contact. Shapeshifters shed their skin during transformation, leaving behind a slick biological residue. They infiltrate human communities and live among us, sometimes for years. Unlike a Skinwalker which is a corrupted human, a Shapeshifter is a distinct non-human species with its own Alpha.",abilities:["Perfect cellular mimicry of any human","Access to copied memories through physical contact","Skin-shedding transformation lasting minutes","Replication of fingerprints, retinal patterns, and voice","Superhuman strength in true form","Silver causes severe pain and injury"],sightings:[{date:"ANCIENT GREECE",text:"Accounts of doppelgangers — exact doubles of living people — appear throughout ancient Greek and Roman literature, described not as ghosts but as physical beings that could eat, speak, and be touched."},{date:"1901, BAVARIA",text:"A man is tried for crimes he claims his double committed. The court records note that witnesses describe both men being seen simultaneously in different locations. The case remains officially unexplained."},{date:"ONGOING",text:"Law enforcement agencies report a statistical anomaly in identity fraud cases where the perpetrator appears to have impossible biometric data — fingerprints, retinal scans, and DNA matching the victim simultaneously."}]},

  {id:44,emoji:"💀",name:"Ghoul",aka:"Graveyard Eater / Al",origin:"Arabia & Middle East",region:"asia",type:"demon",tags:["demon","humanoid","folklore"],threat:75,rarity:55,mapX:505,mapY:135,lore:"From pre-Islamic Arabian mythology, the Ghoul is a shapeshifting demon that inhabits graveyards and deserts, feeding on the flesh of the dead and occasionally the living. It can assume the appearance of the last person it consumed. Ghouls have an obsessive relationship with death — they are drawn to battlefields, cemeteries, and disaster sites. They are among the oldest documented supernatural predators in human history.",abilities:["Shapeshifting into the form of their last meal","Superhuman strength and endurance","Night vision and tracking by scent","Immunity to conventional weapons","Consumption grants access to victim's memories","Can survive indefinitely without feeding"],sightings:[{date:"PRE-7TH CENTURY, ARABIA",text:"The Ghoul appears in pre-Islamic Arabic poetry as a genuine desert predator, described in enough anatomical detail to suggest eyewitness accounts rather than pure mythology."},{date:"1001 NIGHTS ERA",text:"Multiple stories in One Thousand and One Nights treat Ghouls as known hazards of desert travel — practical warnings embedded in fiction, consistent with a real creature known to the authors."},{date:"WORLD WAR I, MIDDLE EAST",text:"British soldiers in the Arabian campaign file reports of creatures disturbing mass graves at night. Officers suppress the reports. Several soldiers are found dead near gravesites with teeth marks inconsistent with any known animal."}]},

  {id:45,emoji:"🧞",name:"Djinn",aka:"Jinn / Wish Demon",origin:"Arabian Peninsula & Islamic World",region:"asia",type:"demon",tags:["demon","spirit","folklore"],threat:79,rarity:62,mapX:508,mapY:138,lore:"Distinct from the divine Ifrit, the Djinn encountered in field reports are predatory creatures that feed on human happiness by trapping victims in elaborate wish-fulfillment hallucinations. The victim experiences their perfect life while the Djinn slowly drains their blood over days or weeks. The hallucination is indistinguishable from reality. Victims die with smiles on their faces, completely drained.",abilities:["Inducing perfect reality-indistinguishable hallucinations","Blood draining over extended periods","Superhuman strength in physical confrontation","Possible teleportation","Can grant genuine wishes at catastrophic cost","Resistance to most conventional harm — burns from lamp oil"],sightings:[{date:"ANCIENT PERSIA",text:"Zoroastrian texts describe Djinn as predatory beings that offer gifts — each gift concealing a hidden price that consumes the recipient. The texts treat them as genuine physical threats, not metaphors."},{date:"MEDIEVAL BAGHDAD",text:"Court physicians in the Abbasid Caliphate document cases of healthy people found comatose with unexplained blood loss in states of apparent bliss. No cause of death is determined. The cases occur in clusters."},{date:"ONGOING, GLOBAL",text:"Unexplained coma cases with characteristic blood loss and expressions of apparent joy continue to be logged by hospitals worldwide with no medical explanation. They appear in clusters and cease without pattern."}]},

  {id:46,emoji:"🦊",name:"Kitsune",aka:"Fox Spirit / Nine-Tailed Fox",origin:"Japan, China & Korea",region:"asia",type:"spirit",tags:["spirit","humanoid","folklore"],threat:65,rarity:70,mapX:720,mapY:105,lore:"A supernatural fox that grows more powerful with age, gaining additional tails — up to nine — as it accumulates centuries of existence. Kitsune can appear as beautiful humans, manipulate dreams, create illusions, and possess people. They feed on the life force of humans through prolonged contact. Ancient Kitsune of nine tails are considered near-divine beings with power rivaling gods. Not inherently evil — some serve as divine messengers.",abilities:["Shapeshifting between fox and human form","Dream manipulation and illusion casting","Life force draining through prolonged contact","Fox-fire: blue or white flames from their tails","Possession of humans","Power increases with each additional tail — up to nine"],sightings:[{date:"HEIAN ERA JAPAN, 794–1185",text:"Court records document multiple cases of noble women behaving strangely, speaking in unknown languages, and displaying knowledge they could not possess. Exorcists called in each case report encountering a fox spirit."},{date:"1233, CHINA",text:"The execution of a woman in Hunan Province accused of being a Kitsune is documented by three separate court scribes. The execution record notes she showed no fear and laughed throughout."},{date:"ONGOING, JAPAN",text:"Inari shrines — dedicated to fox spirits — are the most numerous Shinto shrines in Japan, numbering over 30,000. Unusual phenomena around these shrines continue to be reported by shrine keepers and visitors."}]},

  {id:47,emoji:"🧜",name:"Siren",aka:"Oreichalkos / The Enchantress",origin:"Ancient Greece & Global",region:"europe",type:"demon",tags:["demon","humanoid","aquatic"],threat:80,rarity:60,mapX:455,mapY:98,lore:"Not the bird-women of classical mythology but something far more dangerous — a creature that reads the deepest desires of its target and becomes their perfect person. The Siren releases a powerful biochemical agent through its saliva that creates absolute devotion in victims, who will kill for the Siren without hesitation. The Siren feeds on this devotion. It has no fixed form — it becomes whatever you most need.",abilities:["Biochemical mind control through saliva","Shapeshifting into the target's ideal person","Can read subconscious desires on contact","Commands devoted victims to kill on its behalf","Highly resistant to physical harm","Only bronze dagger or the Siren's own toxin can kill it"],sightings:[{date:"800 BCE, GREECE",text:"Homer's Odyssey documents Sirens in enough practical detail — including the specific countermeasure of wax in ears — to suggest the account is based on genuine encounters rather than pure fiction."},{date:"1843, ATLANTIC OCEAN",text:"A merchant vessel arrives in port with its captain dead and three crew members in custody. All three independently claim they killed the captain to protect a passenger who had since vanished. No passenger was on the manifest."},{date:"ONGOING",text:"A pattern of murder cases where multiple unconnected perpetrators kill someone they love to protect a third party who is never found or identified has been noted by criminologists. No conventional explanation accounts for the behavioral pattern."}]},

  {id:48,emoji:"👶",name:"Changeling",aka:"Fetch / Fairy Child",origin:"Europe (Widespread)",region:"europe",type:"demon",tags:["demon","humanoid","folklore"],threat:58,rarity:68,mapX:390,mapY:72,lore:"A supernatural creature — often a fairy child or demonic entity — left in place of a stolen human child. The Changeling mimics the stolen child perfectly but feeds on the life force of the parents and nearby humans, causing wasting illness in those around it. They are detectable by their inhuman eyes when reflected in certain surfaces. The stolen children are taken to feed something far larger.",abilities:["Perfect mimicry of the stolen child","Life force draining causing wasting illness in caregivers","Superhuman strength when exposed","True form visible in mirrors or reflective surfaces","Resistance to conventional harm","Part of a coordinated feeding network run by a Mother"],sightings:[{date:"MEDIEVAL EUROPE",text:"Thousands of documented cases of Changeling accusations survive in European court and church records. The consistency of the behavioral descriptions — sudden personality change, wasting of parents, strange eyes — across cultures with no contact is remarkable."},{date:"1895, IRELAND",text:"Bridget Cleary is killed by her husband who believes she is a Changeling. The case becomes notorious but anthropologists note the specific behavioral symptoms he describes match those in records centuries older and from unconnected cultures."},{date:"ONGOING",text:"Pediatric medical literature documents a consistent pattern of parents reporting their child seems like a different person following certain illnesses — accompanied by unexplained physical deterioration in the parents themselves."}]},

  {id:49,emoji:"🕸️",name:"Arachne",aka:"The Spider Queen",origin:"Ancient Greece",region:"europe",type:"beast",tags:["beast","humanoid","folklore"],threat:77,rarity:82,mapX:453,mapY:97,lore:"Once a mortal woman transformed by Athena into a spider as punishment for hubris, Arachne has existed for millennia — evolving into something far more dangerous than myth suggests. She spins webs of supernatural strength to cocoon living prey, injecting them with venom that preserves them alive for consumption over weeks. Arachne can appear fully human and hunts by gaining the trust of victims before revealing her true form.",abilities:["Spinning webs of supernatural tensile strength","Paralyzing venom preserving prey alive","Shapeshifting between human and spider-human hybrid form","Wall and ceiling crawling","Thousands of years of predatory cunning","Cocoon construction that resists conventional cutting"],sightings:[{date:"ANCIENT GREECE",text:"Ovid's Metamorphoses documents the transformation of Arachne with specific details of her physical change that read less like poetry and more like a medical description of something the author had access to firsthand accounts of."},{date:"1887, THESSALY GREECE",text:"A shepherd reports finding three men cocooned in an abandoned farmhouse, alive but paralyzed, wrapped in material no known spider produces. All three die before they can be freed. The farmhouse owner has vanished."},{date:"ONGOING",text:"Cases of humans found cocooned in unidentified biological material continue to surface globally. Forensic analysis cannot identify the producer. The material has tensile strength exceeding Kevlar."}]},

  {id:50,emoji:"🔮",name:"Vetala",aka:"Baital / Corpse Spirit",origin:"India",region:"asia",type:"demon",tags:["demon","spirit","folklore"],threat:72,rarity:78,mapX:578,mapY:148,lore:"From ancient Hindu and Buddhist traditions, the Vetala is a spirit that inhabits and animates corpses, preventing them from decomposing. Vastly intelligent and possessed of supernatural knowledge — particularly of past, present, and future — the Vetala is a dangerous interrogator and manipulator. Unlike mindless undead, the Vetala retains full consciousness and personality, using the corpse as a vehicle while hunting.",abilities:["Corpse reanimation and habitation","Precognitive knowledge of past and future","Ability to drive victims to madness","Flight while inhabiting a corpse","Resistance to exorcism without specific Sanskrit mantras","Can abandon and re-enter corpses at will"],sightings:[{date:"1ST CENTURY BCE, INDIA",text:"The Baital Pachisi — 25 tales told by a Vetala to King Vikramaditya — is one of the oldest story collections in existence. Scholars note the frame narrative treats the Vetala as a real known entity with specific behavioral rules."},{date:"COLONIAL ERA, INDIA",text:"British administrators in rural India document multiple cases of exhumed corpses found mobile and coherent. The reports are suppressed as embarrassments but survive in archived correspondence."},{date:"ONGOING, INDIA",text:"Rural communities in Rajasthan and Madhya Pradesh continue to practice specific post-burial rituals explicitly designed to prevent Vetala possession of the deceased. The traditions remain active and largely unbroken."}]},
];
